parameters.jsCode:
const aiResponse = $input.first().json.message?.content || $input.first().json.text || '';
const leadData = $('Extract & Normalize Data').first().json;

let qualification;
try {
  qualification = JSON.parse(aiResponse);
} catch(e) {
  qualification = {
    score: 50,
    category: 'warm',
    summary: 'Could not parse AI response.',
    recommended_action: 'Manual review required.',
    reasoning: 'Parse error.'
  };
}

return [{
  json: {
    ...leadData,
    ...qualification,
    qualified_at: new Date().toISOString()
  }
}];

